INSERT INTO `chat_log` VALUES (1,1,'Can you help me find internships in data science?','Sure, here are some data science internships available.','user','2025-04-22 14:00:26'),(2,2,'How do I post a new job opening?','You can post a job by navigating to the employer dashboard.','user','2025-04-22 14:00:26'),(3,3,'Looking for courses on machine learning.','Here are some top-rated machine learning courses.','user','2025-04-22 14:00:26'),(4,4,'Need assistance with account settings.','Please go to your profile settings to make changes.','user','2025-04-22 14:00:26'),(5,5,'Interested in cybersecurity certifications.','Here are some recognized cybersecurity certification courses.','user','2025-04-22 14:00:26'),(6,6,'What are trending job profiles for data analytics?','Top jobs include Data Analyst, BI Developer, and Data Engineer.','user','2025-04-22 14:00:26'),(7,7,'How do I update the job listing deadline?','Go to the posted job and click on “Edit”.','user','2025-04-22 14:00:26'),(8,8,'I need advanced Python course suggestions.','Try “Python for Data Science” or “Advanced Python Concepts” on Coursera.','user','2025-04-22 14:00:26'),(9,9,'How can I get resume feedback?','Upload your resume and use our Resume Parser tool.','user','2025-04-22 14:00:26'),(10,10,'Is there a free course for cloud basics?','Yes, AWS offers “Cloud Practitioner Essentials” for beginners.','user','2025-04-22 14:00:26'),(11,NULL,'hello','Greetings! How can I assist?','bot','2025-04-22 14:46:00'),(12,NULL,'i want to apply for job','What job title are you applying for?','bot','2025-04-22 14:46:11'),(13,NULL,'hello','Greetings! How can I assist?','user','2025-04-22 14:48:00'),(14,NULL,'i want to apply for job','What job title are you applying for?','user','2025-04-22 14:48:19'),(15,NULL,'Hi','Hello! How can I help you?','user','2025-04-22 18:34:58'),(16,NULL,'How can I apply for a job?','What job title are you applying for?','user','2025-04-22 18:35:12'),(17,NULL,'Frontend Developer','In which location are you applying?','user','2025-04-22 18:35:47'),(18,NULL,'Mumbai','Can I have your email to proceed?','user','2025-04-22 18:36:02'),(19,NULL,'mahajan688@gmail.com','Thanks! I\'ve noted your interest in the {job_title} role. We\'ll contact you at {user_email} shortly. Good luck!','user','2025-04-22 18:36:18'),(20,NULL,'How can I apply for a job?','What job title are you applying for?','user','2025-04-22 18:37:13'),(21,NULL,'Frontend Developer','In which location are you applying?','user','2025-04-22 18:37:22'),(22,NULL,'Mumbai','Can I have your email to proceed?','user','2025-04-22 18:37:30'),(23,NULL,'mahajan688@gmail.com','Thanks! I\'ve noted your interest in the Frontend Developer role. We\'ll contact you at mahajan688@gmail.com shortly. Good luck!','user','2025-04-22 18:37:39'),(24,NULL,'Book a call for job guidance','Enter your email id -','user','2025-04-22 18:38:08'),(25,NULL,'mahajan6@gmail.com','Enter your Phone no -','user','2025-04-22 18:38:20'),(26,NULL,'0987654321','Enter your name','user','2025-04-22 18:38:28'),(27,NULL,'Kunal Mahajan','Thank you for sharing details, we will arrange a session soon.','user','2025-04-22 18:38:35'),(28,NULL,'I want to join the course','Enter Course topic or name which do you want to  enroll','user','2025-04-22 18:38:58'),(29,NULL,'Data Science Bootcamp','Enter your email id','user','2025-04-22 18:39:20'),(30,NULL,'mahajan8@gmail.com','Thanks, you’ve been successfully enrolled. We’ve sent a confirmation to mahajan8@gmail.com. Looking forward to seeing you!','user','2025-04-22 18:39:28'),(31,NULL,'I want to talk with support','What is the support_type?','user','2025-04-22 18:40:46'),(32,NULL,'I\'m facing a technical issue','Thanks for reaching out. I’ll connect you to our support team for technical issues. Please hold on...','user','2025-04-22 18:41:16'),(33,NULL,'Can you recommend a course?','What skill do you want to learn?','user','2025-04-22 18:46:43'),(34,NULL,'Python programming,Machine Learning','Which field or cour