INSERT INTO `courses` VALUES (1,'Data Science Course','Comprehensive course covering data analysis and machine learning.','Python, Pandas, Scikit-learn, SQL',12,'Coursera','https://www.coursera.org/browse/data-science',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(2,'Full Stack Course','Learn to build web applications from scratch.','HTML, CSS, JavaScript, React, Node.js',16,'Udemy','https://www.udemy.com/course/the-complete-web-development-bootcamp/?srsltid=AfmBOorKzoE5ibevkmUqHhdhPK1g1A9895OvQkbYlwtTztPSiKaKLKut&couponCode=ST8MT220425G3',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(3,'Cybersecurity Course','Introduction to cybersecurity principles and practices.','Network Security, Ethical Hacking, Risk Assessment',10,'simplilearn','https://www.simplilearn.com/tutorials/cyber-security-tutorial/cyber-security-for-beginners',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(4,'Cloud Computing Course','Hands-on course on AWS cloud services.','EC2, S3, Lambda, CloudFormation',8,'Pluralsight','https://www.pluralsight.com/browse?=&q=cloud%20architecture%20design&type=all&sort=relevance',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(5,'Mobile App Dev. Course','Develop mobile applications for Android and iOS.','Flutter, Dart, Firebase',14,'Udacity','https://www.udacity.com/course/developing-android-apps-with-kotlin--ud9012',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(6,'Business Analytics Course','Data-driven decision-making using Excel tools.','Excel, Data Visualization, Analytics',6,'LinkedIn Learning','https://www.linkedin.com/learning/topics/microsoft-excel?accountId=222910418&u=222910418&success=true&authUUID=lhLBED7qRDC3As70kz8D7w%3D%3D',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(7,'Backend with Node.js Course','Learn server-side development and NoSQL databases.','Node.js, Express, MongoDB, REST API',10,'Udemy','https://www.udemy.com/course/backend-web-development-with-nodejs-mongo-and-express/?srsltid=AfmBOorChGdZZoFi91IEBn_SZdDe5zANPimFHOvu8dBMAylyJDdteOLn',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(8,'AI Course','Introduction to Artificial Intelligence for non-tech users.','AI Basics, Ethics, Applications',4,'Coursera','https://www.coursera.org/courses?query=artificial%20intelligence&msockid=20528d16e0c4625e13a89806e15f6336',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(9,'DevOps Course','Container orchestration and deployment automation.','Kubernetes, Docker, Helm, CI/CD',8,'Pluralsight','https://www.pluralsight.com/browse?=&q=cloud%20architecture%20design&type=all&sort=relevancekubernetes-devops',1,'2025-04-22 14:00:26','2025-04-23 11:23:41'),(10,'Digital Marketing Course','Hands-on course covering all aspects of digital marketing.','SEO, SEM, Social Media, Google Ads',12,'edX','https://www.edx.org/learn/digital-marketing%27',1,'2025-04-22 14:00:26','2025-04-23 11:23:41');
