INSERT INTO `jobs` VALUES (1,'Data Scientist','Analyze and interpret complex data sets to help decision-making. Requires 2–4 years experience with ML, data mining, and statistical modeling. Strong communication and visualization skills are essential.','Infosys','Bangalore','ML, Python, R ',1,'2025-04-22 14:00:26'),(2,'Frontend Developer','Design and develop user-facing features for responsive web apps. Requires 1–3 years experience in HTML, CSS, JavaScript, and React. Ability to work in agile teams and implement UX/UI best practices is essential.','TCS','Mumbai','HTML, CSS, JavaScript, React',2,'2025-04-22 14:00:26'),(3,'Cybersecurity Analyst','Protect systems and networks from cyber threats. Requires 3–5 years experience in ethical hacking, intrusion detection, and risk assessment. Strong understanding of network protocols and security tools is essential.','Wipro','Hyderabad','Network Security, Ethical Hacking',3,'2025-04-22 14:00:26'),(4,'Cloud Engineer','Deploy and manage scalable cloud infrastructure. Requires 2–4 years experience with AWS, DevOps tools, and scripting. Candidates must understand cloud security, automation, and system performance monitoring.','Amazon','Pune','AWS, DevOps, Linux',4,'2025-04-22 14:00:26'),(5,'Mobile App Developer','Build, test, and maintain mobile applications. Requires 1–2 years of experience in Flutter, Firebase, and UI/UX design. Candidates must have experience with app deployment on Android/iOS platforms.','Flipkart','Delhi','Flutter, Dart, Firebase',5,'2025-04-22 14:00:26'),(6,'Business Analyst','Bridge business needs with data analytics. Requires 2–3 years experience in Excel, SQL, and reporting. Candidates must interpret trends and communicate insights effectively to stakeholders.','Cognizant','Pune','Excel, SQL, Communication',6,'2025-04-22 14:00:26'),(7,'Backend Developer','Develop server-side APIs and maintain databases. Requires 2–4 years experience in Node.js and MongoDB. Candidates must be skilled in writing scalable and secure backend logic.','Zoho','Chennai','Node.js, MongoDB',7,'2025-04-22 14:00:26'),(8,'AI Product Manager','Manage AI product development and delivery. Requires 4+ years experience in AI/ML projects, agile management, and product roadmaps. Strong leadership and collaboration skills are essential.','Google India','Bangalore','AI, Product Management, Agile',8,'2025-04-22 14:00:26'),(9,'DevOps Engineer','Build and maintain CI/CD pipelines and cloud infrastructure. Requires 3+ years experience in Jenkins, Docker, Kubernetes. Candidates must ensure smooth deployments and system uptime.','Tata Communications','Mumbai','Kubernetes, Jenkins, Docker',9,'2025-04-22 14:00:26'),(10,'Digital Marketing Executive','Plan and execute digital marketing strategies. Requires 1–3 years experience in SEO, Google Ads, social media, and analytics tools. Candidates must monitor performance and optimize campaigns.','BYJU’S','Bangalore','SEO, Google Ads, Analytics',10,'2025-04-22 14:00:26');
/*!40000 ALTER TABLE `jobs` ENABLE KEYS */;
